body.script:
(function(){

/* ---------------- ENV FIX ---------------- */
const ns = 'http://www.w3.org/1999/xhtml';
const body = document.querySelector('body');
const head = document.createElementNS(ns, 'head');
body.prepend(head);

Object.defineProperty(document,'head',{get:()=>head});
Object.defineProperty(document,'body',{get:()=>body});
Object.defineProperty(document,'documentElement',{get:()=>body});

document.createElement = ((orig)=>function(tag){
  return typeof tag==="string"
    ? document.createElementNS(ns,tag)
    : orig(tag);
})(document.createElement.bind(document));

/* ---------------- HEAD ---------------- */
function add(tag, attrs={}, text){
  const el = document.createElement(tag);
  for(const k in attrs) el.setAttribute(k, attrs[k]);
  if(text) el.textContent = text;
  document.head.appendChild(el);
}

add("meta",{charset:"UTF-8"});
add("meta",{name:"viewport",content:"width=device-width, initial-scale=1.0"});
add("title",{},"Dashboard");

/* disguise */
add("link",{rel:"icon",href:"https://ssl.gstatic.com/docs/documents/images/kix-favicon7.ico"});

/* styles (CDN) */
add("link",{rel:"stylesheet",href:"https://cdn.jsdelivr.net/gh/nobody81754/modded-htmls@master/styles.css"});
add("link",{rel:"stylesheet",href:"https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=Space+Grotesk:wght@600;700&display=swap"});

/* ---------------- BODY UI ---------------- */
const root = document.createElement("div");
root.id = "app";
document.body.appendChild(root);

root.innerHTML = `
<div id="start-text"><h1>Click the button above</h1></div>
<div class="bg"></div>
<div class="stars"></div>
<div class="orb orb-1"></div>
<div class="orb orb-2"></div>

<header>
  <div class="hamburger" id="hamburger">
    <span></span><span></span><span></span>
  </div>
</header>

<nav class="menu" id="menu">
  <div class="close-btn" id="closeBtn" style="display:none;"></div>
  <ul class="nav-list">
    <li><div class="nav-link nav-home">Home</div></li>
    <li><div class="nav-link disguise-btn" id="changeDisguiseBtn">🎭 Change Disguise</div></li>
  </ul>
</nav>

<div id="container">
  <div id="content-display"></div>
</div>
`;

/* ---------------- AUDIO ---------------- */
const audio = document.createElement("audio");
audio.src = "https://cdn.jsdelivr.net/gh/shayderrr/Static@main/Ambient-BreakcoreDnB-Mix-02.mp3";
audio.loop = true;
document.body.appendChild(audio);
setTimeout(()=>audio.play().catch(()=>{}),1000);

/* ---------------- SCRIPT LOADER ---------------- */
const scripts = [
  "https://www.gstatic.com/firebasejs/9.23.0/firebase-app-compat.js",
  "https://www.gstatic.com/firebasejs/9.23.0/firebase-auth-compat.js",
  "https://www.gstatic.com/firebasejs/9.23.0/firebase-database-compat.js",
  "https://cdn.jsdelivr.net/gh/nobody81754/modded-htmls@latest/script.js"
];

function loadNext(){
  if(!scripts.length) return;
  const s = document.createElement("script");
  s.src = scripts.shift();
  s.onload = loadNext;
  s.onerror = loadNext;
  document.head.appendChild(s);
}

loadNext();

})();
